<script lang="ts">
    export let whatsappNumber = ""; // no '+', digits only
        export let facebookUrl = "#";
            export let tagline = "";
                export let addressLines: string[] = [];
                    export let email = "";

                        function whatsappHref() {
                                const num = (whatsappNumber || "").replace(/[^\d]/g, "");
                                        const text = "Hi, I'd like to enquire about your services.";
                                                if (!num) return `https://wa.me/?text=${encodeURIComponent(text)}`;
                                                        return `https://wa.me/${num}?text=${encodeURIComponent(text)}`;
                                                            }
                                                            </script>

                                                            <footer>
                                                                <div class="footer">
                                                                        <div class="footer-left">
                                                                                    <img class="logo" src="/img/brand/logo.svg" alt="CTRA Group logo" />
                                                                                                <p>{tagline}</p>
                                                                                                        </div>

                                                                                                                <div class="footer-right">
                                                                                                                            <div class="social">
                                                                                                                                            <a
                                                                                                                                                                class="social-link"
                                                                                                                                                                                    href={facebookUrl}
                                                                                                                                                                                                        target="_blank"
                                                                                                                                                                                                                            rel="noreferrer"
                                                                                                                                                                                                                                                aria-label="Facebook"
                                                                                                                                                                                                                                                                >
                                                                                                                                                                                                                                                                                    <i class="fa-brands fa-facebook-f" aria-hidden="true"></i>
                                                                                                                                                                                                                                                                                                    </a>

                                                                                                                                                                                                                                                                                                                    <a
                                                                                                                                                                                                                                                                                                                                        class="social-link"
                                                                                                                                                                                                                                                                                                                                                            href={whatsappHref()}
                                                                                                                                                                                                                                                                                                                                                                                target="_blank"
                                                                                                                                                                                                                                                                                                                                                                                                    rel="noreferrer"
                                                                                                                                                                                                                                                                                                                                                                                                                        aria-label="WhatsApp"
                                                                                                                                                                                                                                                                                                                                                                                                                                        >
                                                                                                                                                                                                                                                                                                                                                                                                                                                            <i class="fa-brands fa-whatsapp" aria-hidden="true"></i>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </a>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <p class="meta">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {#each addressLines as line, i (i)}
